const raw = $input.first().json;
const data = raw?.data || raw || {};
const fileName = $('New Lease Document').item.json.name;
const fileId   = $('New Lease Document').item.json.id;

const cleanNum = v => parseFloat(String(v||0).replace(/[^0-9.]/g,'')) || 0;

// Fallback: parse from summary if structured fields are missing
const summary = data.summary || data.markdown || '';
function fromSummary(pattern, fallback) {
  const m = summary.match(pattern);
  return (m && m[1] && m[1].trim()) ? m[1].trim() : fallback;
}
function numFromSummary(pattern, fallback) {
  const m = summary.match(pattern);
  if (m) { const n = cleanNum(m[1]); if (n > 0) return n; }
  return fallback;
}

const propertyAddress = data.propertyAddress || fromSummary(/Property address:\s*([^.]+)/i, 'N/A');
const landlordName    = data.landlordName    || fromSummary(/Landlord:\s*([^,\.]+)/i, 'N/A');
const tenantName      = data.tenantName      || fromSummary(/Tenant:\s*([^,\.]+)/i, 'N/A');
const leaseStartDate  = data.leaseStartDate  || fromSummary(/(?:Lease commencement|Commencement):\s*([^.]+)/i, 'N/A');
const leaseEndDate    = data.leaseEndDate    || fromSummary(/(?:Lease expiration|Expiration date):\s*([^.]+)/i, 'N/A');
const leaseTerm       = data.leaseTerm       || fromSummary(/Lease term:\s*([^.]+)/i, 'N/A');
const leaseType       = data.leaseType       || fromSummary(/Lease type:\s*([^.]+)/i,
  summary.match(/Triple Net|NNN/i) ? 'Triple Net (NNN)' : 'N/A');
const permittedUse    = data.permittedUse    || fromSummary(/Permitted use:\s*([^.]+)/i, 'N/A');
const renewalOptions  = data.renewalOptionsList || fromSummary(/Renewal options:\s*([^.]+)/i, 'None');
const keyRisks        = data.keyRisksList    || 'None';

const baseRent    = cleanNum(data.baseRentMonthly)          || numFromSummary(/\$([\d,]+)\/month/i, 0);
const annualRent  = cleanNum(data.baseRentAnnual)           || numFromSummary(/\$([\d,]+)\/year/i, baseRent * 12);
const escalation  = cleanNum(data.rentEscalationPct)        || numFromSummary(/escalation:\s*([\d.]+)%/i, 0);
const securityDep = cleanNum(data.securityDeposit)          || numFromSummary(/Security deposit:\s*\$([\d,]+)/i, 0);
const camCharges  = cleanNum(data.camChargesMonthly)        || numFromSummary(/CAM charges:\s*\$([\d,]+)\/month/i, 0);
const camCap      = cleanNum(data.operatingExpensesCap)     || numFromSummary(/cap:\s*([\d.]+)%/i, 0);
const tiAllowance = cleanNum(data.tenantImprovementAllowance) || numFromSummary(/allowance:\s*\$([\d,]+)/i, 0);
const sqFt        = cleanNum(data.usableSquareFeet)         || numFromSummary(/(\d[\d,]+) (?:usable|rentable)/i, 0);
const parkingSpaces = parseInt(data.parkingSpaces)          || numFromSummary(/Parking:\s*(\d+) spaces/i, 0);
const parkingCost = cleanNum(data.parkingCostMonthly)       || numFromSummary(/Parking:.*?\$([\d,]+)\/month/i, 0);

const risks    = keyRisks.split(';').filter(Boolean);
const renewals = renewalOptions.split(';').filter(Boolean);
const terminationAllowed = (data.terminationOptionsList && data.terminationOptionsList !== 'N/A')
  ? 'Yes' : (summary.match(/early termination:\s*yes/i) ? 'Yes' : 'No');

return [{ json: {
  propertyAddress, landlordName, tenantName,
  leaseStartDate, leaseEndDate, leaseTerm, leaseType,
  baseRentMonthly:  baseRent,
  baseRentAnnual:   annualRent,
  rentEscalationPct: escalation,
  securityDeposit:  securityDep,
  camChargesMonthly: camCharges,
  operatingExpensesCap: camCap,
  tenantImprovementAllowance: tiAllowance,
  usableSquareFeet: sqFt,
  parkingSpaces, parkingCost,
  renewalOptionsList: renewalOptions,
  renewalCount: renewals.length,
  permittedUse, keyRisksList: keyRisks, riskCount: risks.length,
  sublettingAllowed: data.sublettingAllowed || !!summary.match(/subletting/i),
  fileName, fileId,
  processedAt: new Date().toISOString(),
  propertyName:      propertyAddress,
  commencementDate:  leaseStartDate,
  expirationDate:    leaseEndDate,
  termYears:         leaseTerm,
  baseRentAmount:    baseRent,
  rentPerSqFt:       sqFt > 0 ? Math.round(annualRent / sqFt) : 0,
  rentFrequency:     'Monthly',
  escalationSummary: escalation + '% annual',
  camAmount:         camCharges,
  camCap:            camCap + '%',
  tiAllowance,
  renewalOptions,
  terminationAllowed,
  terminationFee:    'Per lease terms',
  terminationNotice: 'Per lease terms',
  specialProvisions: permittedUse,
}}];

